let TicketScript={methods:{validateTelField(){let isTel=/^[+]*[(]{0,1}[0-9]{1,4}[)]{0,1}[-\s\./0-9]*$/g;document.querySelectorAll("[field='tel']").forEach((field=>{field.required?field.value&&!0===isTel.test(field.value)?field.hasError=!1:field.hasError=!0:""===field.value.trim()?field.hasError=!1:field.hasError=1==!isTel.test(field.value)}))},async validationForm(containerEl){for(let index=0;index<containerEl.querySelectorAll("[validate]").length;index++){let field=containerEl.querySelectorAll("[validate]")[index];switch(field.tagName.toLowerCase()){case"div":App.validation.validateRadio(field);break;case"ins-input-file":App.validation.validateFile(field);break;case"ins-textarea":App.validation.validateInput(field.querySelector("textarea"));break;default:"password"===field.field?"password_confirmation"===field.id?this.validatePasswordConfirm(field):this.validatePasswordField(field):"email"===field.field?App.validation.validateEmail(field):App.validation.validateInput(field)}}return App.validation.checkInvalidFields(containerEl)},validateCreditCard(currentStep){let cardValid=currentStep.querySelectorAll("#stripe-card[required] .is-invalid"),container=currentStep.querySelector(".validate-credit-card");container&&(cardValid&&cardValid.length>0?(container.querySelector(".error-message").classList.remove("hide"),TicketScript.methods.creditCardsHasError(container,!0)):(container.querySelector(".error-message").classList.add("hide"),TicketScript.methods.creditCardsHasError(container,!1)))},creditCardsHasError(step,error){step.querySelectorAll(".card-options ins-credit-card").forEach((element=>{error?element.classList.add("is-invalid"):element.classList.remove("is-invalid")}))},async validateForm(event,groupElem){event&&event.preventDefault();let formId=event.target.id,formElem=document.getElementById(formId).closest("form");if(event.srcElement,"submit-purchase"==formId||"submit-billing-info"==formId||"checkout-ticket-submit-btn"==formId){let isValid=await this.validationForm(groupElem);if("submit-purchase"==formId||"submit-billing-info"==formId)return isValid;let checkCC=!1;if("checkout-ticket-submit-btn"==formId){let subTotalFormEl=document.getElementById("bill-order-value"),totalFormEl=document.getElementById("bill-total-amount"),subTotal=subTotalFormEl&&subTotalFormEl.value||0,grandTotal=totalFormEl&&totalFormEl.value||0;0==subTotal&&0==grandTotal?(checkCC=!0,isValid=!0):(checkCC=await this.validationForm(groupElem),TicketScript.methods.validateCreditCard(groupElem))}if(isValid&&checkCC)return!0}else if(await App.validation.validateForm(formElem))return formElem.submit(),!0}}};